import{_ as t,o as n,c as o,a0 as s}from"./chunks/framework.BWpMpcZ2.js";const p=JSON.parse('{"title":"Context Settings","description":"","frontmatter":{},"headers":[],"relativePath":"configuration/context.md","filePath":"configuration/context.md"}'),a={name:"configuration/context.md"};function r(i,e,l,d,c,h){return n(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="context-settings" tabindex="-1">Context Settings <a class="header-anchor" href="#context-settings" aria-label="Permalink to &quot;Context Settings&quot;">​</a></h1><p>Context settings control what information the AI receives about your project. This is the most important section -- getting context right is the key to useful AI assistance.</p><h2 id="session-memory" tabindex="-1">Session Memory <a class="header-anchor" href="#session-memory" aria-label="Permalink to &quot;Session Memory&quot;">​</a></h2><p>margin remembers your recent conversation turns (questions and AI responses) to keep the discussion coherent.</p><ul><li><strong>Max History Depth</strong>: Set between 1 and 10 turns. A higher number gives the AI more context but uses more tokens. The default of 5 works well for most conversations.</li></ul><h2 id="include-document-structure" tabindex="-1">Include Document Structure <a class="header-anchor" href="#include-document-structure" aria-label="Permalink to &quot;Include Document Structure&quot;">​</a></h2><p>When enabled, the AI receives a structural outline (paragraph previews) of your active document. This helps the Planner understand the broader story flow, but consumes more tokens.</p><div class="warning custom-block"><p class="custom-block-title">Consider turning this off if you&#39;re using a smaller local model. The outline can consume a significant portion of your context window.</p></div><h2 id="additional-context" tabindex="-1">Additional Context <a class="header-anchor" href="#additional-context" aria-label="Permalink to &quot;Additional Context&quot;">​</a></h2><p>Write any extra instructions that should be prepended to every AI request. This is useful for persistent preferences:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Always use British spelling.</span></span>
<span class="line"><span>Avoid passive voice.</span></span>
<span class="line"><span>Keep paragraphs under 4 sentences.</span></span></code></pre></div><p>These instructions are added automatically to the Writer and Chat agents. The Planner intentionally does not receive them.</p><h2 id="reference-files" tabindex="-1">Reference Files <a class="header-anchor" href="#reference-files" aria-label="Permalink to &quot;Reference Files&quot;">​</a></h2><p>The <strong>Reference Files</strong> panel lets you control which files in your workspace the AI can read. Each file has three states:</p><table tabindex="0"><thead><tr><th>State</th><th>Icon</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Available</strong> (default)</td><td><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M2.062 12.348a1 1 0 0 1 0-.696 10.75 10.75 0 0 1 19.876 0 1 1 0 0 1 0 .696 10.75 10.75 0 0 1-19.876 0"></path><circle cx="12" cy="12" r="3"></circle></svg></td><td>The Planner can read this file if it decides the content is relevant.</td></tr><tr><td><strong>Pinned</strong></td><td><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 17v5"></path><path d="M9 10.76a2 2 0 0 1-1.11 1.79l-1.78.9A2 2 0 0 0 5 15.24V16a1 1 0 0 0 1 1h12a1 1 0 0 0 1-1v-.76a2 2 0 0 0-1.11-1.79l-1.78-.9A2 2 0 0 1 15 10.76V7a1 1 0 0 1 1-1 2 2 0 0 0 0-4H8a2 2 0 0 0 0 4 1 1 0 0 1 1 1z"></path></svg></td><td>This file is always included in every AI request. Good for style guides or world-building rules.</td></tr><tr><td><strong>Blocked</strong></td><td><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#ef4444" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10.733 5.076a10.744 10.744 0 0 1 11.205 6.575 1 1 0 0 1 0 .696 10.747 10.747 0 0 1-1.444 2.49"></path><path d="M14.084 14.158a3 3 0 0 1-4.242-4.242"></path><path d="M17.479 17.499a10.75 10.75 0 0 1-15.417-5.151 1 1 0 0 1 0-.696 10.75 10.75 0 0 1 4.446-5.143"></path><path d="m2 2 20 20"></path></svg></td><td>The AI is prevented from reading this file. Useful when smaller models struggle with too much context.</td></tr></tbody></table><p>Click a file&#39;s icon to cycle through the states.</p><p>You can also block an entire folder -- all files within it become inaccessible to the AI. Blocked folders are shown with a red strikethrough in the panel.</p>`,17)])])}const g=t(a,[["render",r]]);export{p as __pageData,g as default};
